SKILL = {'name': 'youtube_playlist_parser', 'keywords': ['youtube', 'playlist', 'url parsing', 'video metadata', 'regex validation'], 'prompt_fragment': 'Validate YouTube playlist URLs using urllib and regex, extract video IDs and titles. Return simulated metadata as (video_id, title) tuples. Raise ValueError for malformed URLs or unsupported formats. Ensure non-empty results with valid IDs and titles. Separate parsing logic from test execution. Use type hints for clarity and maintainability.', 'example_code': 'import re\nimport urllib.parse\nfrom typing import List, Tuple\n\ndef parse_playlist_url(url: str) -> List[Tuple[str, str]]:\n    parsed = urllib.parse.urlparse(url)\n    if parsed.scheme not in ("http", "https") or "youtube.com" not in parsed.netloc:\n        raise ValueError("Invalid URL")\n    query = urllib.parse.parse_qs(parsed.query)\n    playlist_id = query.get("list", [None])[0]\n    if not playlist_id:\n        raise ValueError("Invalid URL")\n    if not re.match(r"^(PL|LL)[\\w-]{10,}$", playlist_id):\n        raise ValueError("Invalid URL")\n    return [("dQw4w9WgXcQ", "Never Gonna Give You Up")]', 'language': 'python'}
